    // ...existing fields...

    #[serde(default)]
    pub self_healing: SelfHealingConfig,
}

impl RchConfig {
    pub fn load() -> Result<Self> {
        let config = /* load from file or default */;
        // Apply env overrides
        Ok(Self {
            self_healing: config.self_healing.with_env_overrides(),
            ..config
        })
    }
}
```

